def findAllConcatenatedWordsInADict(words):
    wordSet = set(words)
    res = []
    memo = {}
    def canSplit(word):
        if word in memo: return memo[word]
        for i in range(1, len(word)):
            prefix = word[:i]
            suffix = word[i:]
            if prefix in wordSet and (suffix in wordSet or canSplit(suffix)):
                memo[word] = True; return True
        memo[word] = False; return False
    for w in words:
        if canSplit(w): res.append(w)
    return res

